#!/bin/bash
# AEON NOAA APT PIPELINE: rtl_fm-demodulated audio -> live APT scanline frame.
#
# Two modes:
#   pass-aware (default): query aeon_noaa_pass_schedule.py for the next visible
#                         NOAA-15/18/19 pass, sleep until lead-time before AOS,
#                         tune to that satellite's freq for the pass duration,
#                         then loop. Set AEON_NOAA_LAT and AEON_NOAA_LON.
#   manual: pass a frequency as $1 (or set AEON_NOAA_MANUAL=1) to use legacy
#           single-freq behavior — useful for debug captures off-pass.

set -u

log_gateway() {
    echo "[NOAA-APT] $1" >> gateway.log
    echo "[NOAA-APT] $1" >&2
}

if ! command -v rtl_fm >/dev/null 2>&1; then
    log_gateway "rtl_fm not found; cannot demodulate NOAA APT audio"
    exit 1
fi

if [ ! -x ./target/release/noaa-apt-audio-frame ]; then
    log_gateway "noaa-apt-audio-frame missing; run cargo build --release --bin noaa-apt-audio-frame"
    exit 127
fi

NOAA_DEBUG_LINES=${AEON_NOAA_DEBUG_LINES:-80}
NOAA_PUBLISH_MS=${AEON_NOAA_PUBLISH_MS:-150}
NOAA_PUBLISH_LINES=${AEON_NOAA_PUBLISH_LINES:-1}
# NOAA APT is a ~34-40 kHz wide WFM signal carrying a 2400 Hz AM subcarrier.
NOAA_RF_SAMPLE_RATE=${AEON_NOAA_RF_SAMPLE_RATE:-48000}
NOAA_WAV_OUTPUT=${AEON_NOAA_WAV_OUTPUT:-imaging/noaa_apt_live.wav}
# R820T tuner; 49.6 dB is the max gain step. PPM correction can be set per
# device with AEON_NOAA_PPM (default 0).
NOAA_GAIN_DB=${AEON_NOAA_GAIN_DB:-49.6}
NOAA_PPM=${AEON_NOAA_PPM:-0}
# Default offset 0: rtl_fm's -f sets the actual receive frequency. Any nonzero
# offset places the carrier outside the post-decimation passband.
RTLFM_TUNE_OFFSET_HZ=${AEON_NOAA_RTLFM_TUNE_OFFSET_HZ:-0}
# Pass-aware loop knobs.
SCHEDULER="$(dirname "$0")/aeon_noaa_pass_schedule.py"
NOAA_LEAD_S=${AEON_NOAA_LEAD_S:-30}            # start rtl_fm this many sec before AOS
NOAA_TRAIL_S=${AEON_NOAA_TRAIL_S:-30}          # keep capturing past LOS by this many sec
NOAA_MIN_ELEV=${AEON_NOAA_MIN_ELEV:-25}        # ignore passes below this max elevation
NOAA_LAT=${AEON_NOAA_LAT:-}
NOAA_LON=${AEON_NOAA_LON:-}

run_pipeline() {
    local freq_hz="$1"
    local duration_s="$2"
    local label="$3"
    local tune_freq=$((freq_hz + RTLFM_TUNE_OFFSET_HZ))
    log_gateway "▶ ${label}: rtl_fm freq=${freq_hz} Hz (tune=${tune_freq} Hz) gain=${NOAA_GAIN_DB} dB ppm=${NOAA_PPM} duration=${duration_s}s"

    # Flag rationale (vs prior `-M fm -E dc -g 30`):
    #   -M wbfm : wideband FM (~200 kHz aperture) so the full ~34 kHz APT
    #             spectrum survives demodulation. `-M fm` is narrowband
    #             (~12.5 kHz) and discards most of the AM subcarrier sidebands.
    #   -E deemp: 75 µs FM de-emphasis. Without it the demodulated audio is
    #             dominated by HF hash and the 2400 Hz AM subcarrier is buried.
    #   -F 9    : enable the higher-quality post-decimation FIR filter.
    #   -g 49.6 : max R820T gain step.
    timeout --foreground "${duration_s}s" \
        rtl_fm -f "$tune_freq" -M wbfm -s "$NOAA_RF_SAMPLE_RATE" \
            -g "$NOAA_GAIN_DB" -p "$NOAA_PPM" -F 9 -E deemp -l 0 - 2>>sdr_bridge.log \
    | timeout --foreground "$((duration_s + 5))s" \
        ./target/release/noaa-apt-audio-frame \
            --input-rate "$NOAA_RF_SAMPLE_RATE" \
            --freq-hz "$freq_hz" \
            --output noaa_apt.frame \
            --publish-lines "$NOAA_PUBLISH_LINES" \
            --debug-lines "$NOAA_DEBUG_LINES" \
            --publish-ms "$NOAA_PUBLISH_MS" \
            --source-id "$label" \
            ${NOAA_WAV_OUTPUT:+--wav-output "$NOAA_WAV_OUTPUT"} 2>>sdr_bridge.log
    log_gateway "■ ${label}: rtl_fm exited"
}

# ---- Manual mode (back-compat) -----------------------------------------------
if [ -n "${1:-}" ] || [ "${AEON_NOAA_MANUAL:-0}" = "1" ]; then
    FREQ="${1:-${AEON_NOAA_FREQ:-137100000}}"
    DUR="${AEON_NOAA_MANUAL_DURATION:-900}"
    run_pipeline "$FREQ" "$DUR" "noaa_apt_manual"
    exit $?
fi

# ---- Pass-aware mode ---------------------------------------------------------
if [ -z "$NOAA_LAT" ] || [ -z "$NOAA_LON" ]; then
    log_gateway "pass-aware mode requires AEON_NOAA_LAT and AEON_NOAA_LON (or pass FREQ as \$1 for manual mode)"
    exit 2
fi
if [ ! -x "$SCHEDULER" ]; then
    log_gateway "scheduler not found at $SCHEDULER"
    exit 127
fi

log_gateway "pass-aware mode @ ${NOAA_LAT},${NOAA_LON} min_elev=${NOAA_MIN_ELEV}° lead=${NOAA_LEAD_S}s trail=${NOAA_TRAIL_S}s"

while true; do
    # Prefer an in-progress pass if one is already up; otherwise next-future one.
    if line="$("$SCHEDULER" --lat "$NOAA_LAT" --lon "$NOAA_LON" \
                            --min-elev "$NOAA_MIN_ELEV" active 2>>sdr_bridge.log)"; then
        :
    elif line="$("$SCHEDULER" --lat "$NOAA_LAT" --lon "$NOAA_LON" \
                              --min-elev "$NOAA_MIN_ELEV" next 2>>sdr_bridge.log)"; then
        :
    else
        log_gateway "no upcoming pass found; sleeping 600s before retry"
        sleep 600
        continue
    fi

    epoch=$(echo "$line" | awk '{print $1}')
    name=$(echo "$line" | awk '{print $2}')
    freq=$(echo "$line" | awk '{print $3}')
    dur=$(echo "$line" | awk '{print $4}')
    el=$(echo "$line" | awk '{print $5}')

    now=$(date +%s)
    wait_s=$(( epoch - NOAA_LEAD_S - now ))
    if [ "$wait_s" -gt 0 ]; then
        log_gateway "next pass: ${name} @ ${freq} Hz, AOS in ${wait_s}s (max_el=${el}°, dur=${dur}s)"
        sleep "$wait_s"
    else
        log_gateway "pass already in progress: ${name} @ ${freq} Hz (max_el=${el}°, dur=${dur}s)"
    fi

    capture_s=$(( dur + NOAA_LEAD_S + NOAA_TRAIL_S ))
    if [ "$capture_s" -lt 60 ]; then capture_s=60; fi
    run_pipeline "$freq" "$capture_s" "${name}_$(date -u +%Y%m%dT%H%M%SZ)"

    # Small idle so we don't tight-loop if the scheduler returns the same pass.
    sleep 5
done
